import jsonStringify from"fastest-stable-stringify";import*as Schema from"../schema.js";import*as Instance from"../instance.js";const id="https://json-schema.org/keyword/uniqueItems",compile=e=>Schema.value(e),interpret=(e,t)=>{if(!Instance.typeOf(t,"array")||!1===e)return!0;e=Instance.value(t).map(jsonStringify);return new Set(e).size===e.length};export default{id:id,compile:compile,interpret:interpret};